<script>
import {
    authorLink,
    publishLink,
    showAvatar,
    resolveImagePath,
    getThumbnail
} from "@jx3box/jx3box-common/js/utils";
import { __ossMirror } from "@jx3box/jx3box-common/js/jx3box.json";
import lodash from "lodash";
import { showTime,showRecently } from "@/utils/moment.js";
import { getTeams } from "@/service/team.js";
import servers from "@jx3box/jx3box-data/data/server/server_list.json";
export default {
    name: "Team",
    props: [],
    data: function() {
        return {
            per: 10,
            page: 1,
            total: 1,
            pages: 1,
            data: [
                // {
                //     ID: 13,
                //     status: 1,
                //     super: 6314,
                //     admin: "",
                //     server: "服务器名",
                //     name: "团队名字",
                //     desc: "",
                //     logo: "",
                //     recruit: "招2个七秀",
                //     found: "",
                //     time: "",
                //     contact: "",
                //     tv: "",
                //     created_at: "2020-10-06T16:29:17+08:00",
                //     updated_at: "2020-10-06T16:29:17+08:00",
                //     deleted_at: "0001-01-01T00:00:00Z",
                // },
            ],
            loading: false,
            name: "",
            server: "",
            servers,
        };
    },
    computed: {
        params: function() {
            return {
                pageIndex: this.page,
                pageSize: this.per,
                recruit: 1,     //有招募的
                server: this.server,
                name: this.name,
            };
        },
    },
    methods: {
        loadData: function() {
            this.loading = true;
            getTeams(this.params)
                .then((res) => {
                    this.total = res.data.data.page.total;
                    this.pages = res.data.data.page.pageTotal;
                    this.data = res.data.data.list;
                })
                .finally(() => {
                    this.loading = false;
                });
        },
    },
    filters: {
        showTime: showRecently,
        showLogo: function (val){
            return getThumbnail(val,42,true)
        },
    },
    watch: {
        params: function(newparams) {
            this.loadData();
        },
    },
    mounted: function() {
        this.loadData();
    },
    components: {},
};
</script>

